      !p.includes('node_modules') &&
      /\.(js|ts|jsx|tsx|mjs|cjs)$/.test(p) &&
      !/\.d\.ts$/.test(p) &&
      !isTestOrExampleFile(p)
    )
    .sort((a, b) => scoreFile(b) - scoreFile(a))
    .slice(0, scanLimit);
}

// ── Env-dependent behavior detection ───────────────────────────
function hasEnvDependentBehavior(deps, scripts, tree, hasServerSource) {
  const depsList = Object.keys(deps);
  const serverFrameworks = ['express', 'fastify', 'koa', 'hapi', 'restify', 'connect', 'polka', 'micro', 'http-server', 'serve-static', 'next', 'nuxt', 'remix', 'astro', '@astrojs', 'sveltekit', 'gatsby', 'eleventy', 'nitro', 'h3'];
  const dbOrms = ['prisma', 'drizzle-orm', 'sequelize', 'mongoose', 'typeorm', 'mikro-orm', 'knex', 'pg', 'mysql2', 'mongodb', 'redis', 'ioredis', '@prisma/client'];
  const httpClients = ['axios', 'got', 'node-fetch', 'undici', 'superagent', 'request', 'ky'];
  const deployTools = ['wrangler', '@vercel/node', '@netlify/functions', 'serverless', 'aws-sdk', '@aws-sdk', '@pulumi', 'cdktf', 'firebase', '@google-cloud'];

  const hasRelevantDep = [...serverFrameworks, ...dbOrms, ...httpClients, ...deployTools].some(d => depsList.includes(d));
  const hasServerScript = /\b(start|serve|dev|preview|deploy)\b/.test(JSON.stringify(scripts || {}));
  const hasDeployConfig = tree.some(p =>
    /(^|\/)Dockerfile$/.test(p) ||
    /(^|\/)docker-compose\.ya?ml$/.test(p) ||
    /wrangler\.(toml|json)$/.test(p) ||
    p === 'vercel.json' ||
    p === 'netlify.toml' ||
    /fly\.toml$/.test(p) ||
    /serverless\.(yml|yaml|json)$/.test(p)
  );

  return hasRelevantDep || hasServerScript || hasDeployConfig || hasServerSource;
}

export async function check(context) {
  const { tree, files, packageJson, repoType } = context;

  try {
    if (repoType === RepoType.EMPTY) {
      return { checkId, status: 'not-applicable', confidence: 'high', message: 'Empty repo — no env vars needed', findings: [] };
    }

    const deps = { ...packageJson?.dependencies, ...packageJson?.devDependencies } || {};
    const devDeps = packageJson?.devDependencies || {};
    const scripts = packageJson?.scripts || {};
    const scriptsStr = JSON.stringify(scripts);

    // Fast tree-level signals
    const hasEnvFile = tree.some(p => /(^|\/)\.env(\.|$)/.test(p) && !p.includes('node_modules'));
    const hasDotenvDep = !!(deps.dotenv || deps['@dotenvx/dotenvx'] || deps['dotenv-expand'] || devDeps.dotenv);
    const hasEnvInScripts = /\b(?:NODE_ENV|cross-env|dotenvx|dotenv|env-cmd)\b/.test(scriptsStr);

    // Scan prioritized source files
    const sourceFiles = buildFileList(tree, 35);
    const { foundPattern, foundDotenvSetup, hasServerSource, hardcodedFindings } = await scanSourceFiles(sourceFiles, files);

    // ── Layer 1: actual env usage in code ──────────────────────
    if (foundPattern) {
      const parts = [];
      if (hasDotenvDep || foundDotenvSetup) parts.push('dotenv configured');
      if (hasEnvFile) parts.push('.env file present');
      const info = parts.join(', ') || `${foundPattern} usage found`;
      return { checkId, status: 'pass', confidence: 'high', message: `Uses environment variables (${info})`, findings: [] };
    }

    // ── Layer 2: strong env documentation / tooling signals ────
    if (hasEnvFile) {
      return { checkId, status: 'pass', confidence: 'high', message: 'Uses environment variables (.env file present)', findings: [] };
    }
    if (hasDotenvDep) {
      return { checkId, status: 'pass', confidence: 'high', message: 'Uses environment variables (dotenv dependency)', findings: [] };
    }
    if (hasEnvInScripts) {
      return { checkId, status: 'pass', confidence: 'high', message: 'Uses environment variables (env referenced in scripts)', findings: [] };
    }

    // ── Layer 3: monorepo / workspace env declarations ─────────
    const hasTurboJson = tree.some(p => p.endsWith('turbo.json') && !p.includes('node_modules'));
    if (hasTurboJson) {
      const turboPath = tree.find(p => p.endsWith('turbo.json') && !p.includes('node_modules'));
      if (turboPath) {
        try {
          const content = await files.get(turboPath);
          if (content && /"globalEnv"|"env"\s*:/.test(content)) {
            return { checkId, status: 'pass', confidence: 'high', message: 'Uses environment variables (turborepo env config)', findings: [] };
          }
        } catch (e) { /* ignore */ }
      }
    }

    const subPackages = tree.filter(p => p.endsWith('package.json') && p !== 'package.json' && !p.includes('node_modules'));
    if (subPackages.length > 0) {
      for (const pkgPath of subPackages.slice(0, 5)) {
        try {
          const content = await files.get(pkgPath);
          if (content && /\b(?:NODE_ENV|cross-env|dotenvx|dotenv|env-cmd|process\.env)\b/.test(content)) {
            return { checkId, status: 'pass', confidence: 'high', message: 'Uses environment variables (workspace package env usage)', findings: [] };
          }
        } catch (e) { /* ignore */ }
      }
    }

    // ── Layer 4: library exception ─────────────────────────────
    if (repoType === RepoType.LIBRARY) {
      return { checkId, status: 'not-applicable', confidence: 'medium', message: 'Library — env var usage not required', findings: [] };
    }

    // ── Layer 5: hardcoded config values (mutant catch) ────────
    if (hardcodedFindings.length > 0) {
      return {
        checkId,
        status: 'check-it',
        confidence: 'high',
        message: 'Deployment configuration appears hardcoded; no environment variables detected',
        findings: hardcodedFindings,
      };
    }

    // ── Layer 6: deployment-related code without env vars ──────
    const envDependent = hasEnvDependentBehavior(deps, scripts, tree, hasServerSource);
    if (envDependent) {
      return {
        checkId,
        status: 'check-it',
        confidence: 'medium',
        message: 'No environment variable usage detected despite deployment-related code',
        findings: [{ file: 'N/A', issue: 'Repo contains server, deploy, or network code but no env var usage or .env documentation found' }],
      };
    }

    // ── Layer 7: no env need detected ──────────────────────────
    return { checkId, status: 'not-applicable', confidence: 'medium', message: 'No environment-dependent behavior detected — env vars not required', findings: [] };

  } catch (err) {
    console.error(err);
    return { checkId, status: 'check-it', confidence: 'low', message: `Error: ${err.message}`, findings: [{ file: 'N/A', issue: err.message }] };
  }
}
